{
  "name": "StatusGuard Pro",
  "description": "A high-performance service availability and SLA monitoring dashboard featuring real-time status updates, regional component tracking, and incident management with AI-assisted reporting."
}

export enum Severity {
  OPERATIONAL = 'OPERATIONAL',
  DEGRADED = 'DEGRADED',
  OUTAGE = 'OUTAGE'
}

export interface Component {
  id: string;
  regionId: string;
  name: string;
  description: string;
}

export interface Region {
  id: string;
  name: string;
  components: Component[];
}

export interface Incident {
  id: string;
  componentId: string;
  title: string;
  description: string;
  severity: Severity;
  startTime: string; // ISO string
  endTime: string | null; // null if ongoing
}

export interface SLAData {
  componentId: string;
  availability90Days: number;
  uptimeHistory: boolean[]; // 90 booleans representing last 90 days
}

export interface AppState {
  regions: Region[];
  incidents: Incident[];
  isAuthenticated: boolean;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI } from "@google/genai";

export const generateIncidentDescription = async (
  componentName: string,
  severity: string,
  issueDescription: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview';

  const prompt = `Act as a professional Site Reliability Engineer. Generate a concise, clear status page update for a component named "${componentName}". 
  The severity is "${severity}". The internal issue is: "${issueDescription}". 
  Provide a user-friendly public message that acknowledges the problem and mentions that teams are investigating. 
  Output ONLY the message text without any prefixes or quotes.`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text?.trim() || "We are currently investigating issues with this component. Updates will follow shortly.";
  } catch (error) {
    console.error("Gemini API error:", error);
    return "Issue detected. We are investigating and will provide updates soon.";
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { AppState, Region, Incident, Severity, Component } from './types';

interface AppContextType {
  state: AppState;
  addRegion: (name: string) => void;
  removeRegion: (id: string) => void;
  addComponent: (regionId: string, name: string, description: string) => void;
  removeComponent: (regionId: string, componentId: string) => void;
  reportIncident: (incident: Omit<Incident, 'id'>) => void;
  resolveIncident: (incidentId: string) => void;
  login: () => void;
  logout: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const INITIAL_DATA: AppState = {
  regions: [
    {
      id: 'reg-1',
      name: 'North America (US-East)',
      components: [
        { id: 'comp-1', regionId: 'reg-1', name: 'API Gateway', description: 'Core authentication and routing' },
        { id: 'comp-2', regionId: 'reg-1', name: 'Web Dashboard', description: 'Primary user interface' },
      ],
    },
    {
      id: 'reg-2',
      name: 'Europe (EU-West)',
      components: [
        { id: 'comp-3', regionId: 'reg-2', name: 'Database Cluster', description: 'Data storage layer' },
      ],
    }
  ],
  incidents: [],
  isAuthenticated: false,
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('statusguard_state');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('statusguard_state', JSON.stringify(state));
  }, [state]);

  const addRegion = useCallback((name: string) => {
    setState(prev => ({
      ...prev,
      regions: [...prev.regions, { id: `reg-${Date.now()}`, name, components: [] }]
    }));
  }, []);

  const removeRegion = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      regions: prev.regions.filter(r => r.id !== id)
    }));
  }, []);

  const addComponent = useCallback((regionId: string, name: string, description: string) => {
    setState(prev => ({
      ...prev,
      regions: prev.regions.map(r => r.id === regionId ? {
        ...r,
        components: [...r.components, { id: `comp-${Date.now()}`, regionId, name, description }]
      } : r)
    }));
  }, []);

  const removeComponent = useCallback((regionId: string, componentId: string) => {
    setState(prev => ({
      ...prev,
      regions: prev.regions.map(r => r.id === regionId ? {
        ...r,
        components: r.components.filter(c => c.id !== componentId)
      } : r)
    }));
  }, []);

  const reportIncident = useCallback((incident: Omit<Incident, 'id'>) => {
    setState(prev => ({
      ...prev,
      incidents: [...prev.incidents, { ...incident, id: `inc-${Date.now()}` }]
    }));
  }, []);

  const resolveIncident = useCallback((incidentId: string) => {
    setState(prev => ({
      ...prev,
      incidents: prev.incidents.map(inc => inc.id === incidentId ? { ...inc, endTime: new Date().toISOString() } : inc)
    }));
  }, []);

  const login = useCallback(() => setState(prev => ({ ...prev, isAuthenticated: true })), []);
  const logout = useCallback(() => setState(prev => ({ ...prev, isAuthenticated: false })), []);

  return (
    <AppContext.Provider value={{
      state,
      addRegion,
      removeRegion,
      addComponent,
      removeComponent,
      reportIncident,
      resolveIncident,
      login,
      logout
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React from 'react';
import { Severity } from '../types';

interface UptimeGraphProps {
  componentId: string;
  days?: number;
}

const UptimeGraph: React.FC<UptimeGraphProps> = ({ componentId, days = 90 }) => {
  // Mock uptime logic: Higher indices are more recent.
  // In a real app, this would be computed from incident history.
  const history = React.useMemo(() => {
    return Array.from({ length: days }).map((_, i) => {
      // Simulate occasional hiccups
      const rand = Math.random();
      if (rand > 0.98) return Severity.OUTAGE;
      if (rand > 0.95) return Severity.DEGRADED;
      return Severity.OPERATIONAL;
    });
  }, [componentId, days]);

  const getDayColor = (status: Severity) => {
    switch (status) {
      case Severity.OUTAGE: return 'bg-red-500';
      case Severity.DEGRADED: return 'bg-yellow-400';
      default: return 'bg-emerald-500';
    }
  };

  return (
    <div className="mt-2 group relative">
      <div className="flex gap-[2px] h-8 items-end">
        {history.map((status, i) => (
          <div
            key={i}
            className={`flex-1 h-full rounded-[1px] ${getDayColor(status)} opacity-80 hover:opacity-100 transition-opacity cursor-help`}
            title={`Day ${days - i}: ${status.toLowerCase()}`}
          />
        ))}
      </div>
      <div className="flex justify-between mt-1 text-[10px] text-gray-400 font-medium">
        <span>{days} days ago</span>
        <span className="text-gray-300">|</span>
        <span>Today</span>
      </div>
    </div>
  );
};

export default UptimeGraph;

import React from 'react';
import { useApp } from '../store';
import { Severity } from '../types';
import UptimeGraph from './UptimeGraph';

const PublicDashboard: React.FC = () => {
  const { state } = useApp();

  const getComponentStatus = (componentId: string) => {
    const activeIncidents = state.incidents.filter(i => i.componentId === componentId && !i.endTime);
    if (activeIncidents.find(i => i.severity === Severity.OUTAGE)) return Severity.OUTAGE;
    if (activeIncidents.find(i => i.severity === Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const globalStatus = React.useMemo(() => {
    const statuses = state.regions.flatMap(r => r.components.map(c => getComponentStatus(c.id)));
    if (statuses.includes(Severity.OUTAGE)) return { label: 'System Outage', color: 'bg-red-600', sub: 'Some systems are experiencing major issues' };
    if (statuses.includes(Severity.DEGRADED)) return { label: 'Partial Degradation', color: 'bg-yellow-500', sub: 'We are investigating slowed performance in some areas' };
    return { label: 'All Systems Operational', color: 'bg-emerald-500', sub: 'Everything is running smoothly' };
  }, [state]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      {/* Global Status Header */}
      <div className={`${globalStatus.color} rounded-xl p-8 text-white shadow-lg mb-12 transition-all`}>
        <h1 className="text-3xl font-bold mb-2">{globalStatus.label}</h1>
        <p className="opacity-90">{globalStatus.sub}</p>
      </div>

      {/* Incidents Section */}
      {state.incidents.filter(i => !i.endTime).length > 0 && (
        <div className="mb-12">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
            Active Incidents
          </h2>
          <div className="space-y-4">
            {state.incidents.filter(i => !i.endTime).map(incident => (
              <div key={incident.id} className="bg-white border border-gray-200 rounded-lg p-6 shadow-sm">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg">{incident.title}</h3>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                    incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {incident.severity}
                  </span>
                </div>
                <p className="text-gray-600 mb-4">{incident.description}</p>
                <div className="text-xs text-gray-400">
                  Started: {new Date(incident.startTime).toLocaleString()}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Regions and Components */}
      <div className="space-y-10">
        {state.regions.map(region => (
          <div key={region.id}>
            <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest mb-4">{region.name}</h2>
            <div className="bg-white border border-gray-200 rounded-xl divide-y divide-gray-100 shadow-sm overflow-hidden">
              {region.components.length === 0 ? (
                <div className="p-6 text-center text-gray-400 italic">No components configured.</div>
              ) : (
                region.components.map(comp => {
                  const status = getComponentStatus(comp.id);
                  return (
                    <div key={comp.id} className="p-6 hover:bg-gray-50 transition-colors">
                      <div className="flex justify-between items-center mb-2">
                        <div>
                          <h3 className="font-semibold text-gray-800">{comp.name}</h3>
                          <p className="text-xs text-gray-500">{comp.description}</p>
                        </div>
                        <div className="flex items-center gap-2">
                          <span className={`text-sm font-medium ${
                            status === Severity.OPERATIONAL ? 'text-emerald-600' :
                            status === Severity.DEGRADED ? 'text-yellow-600' : 'text-red-600'
                          }`}>
                            {status.toLowerCase()}
                          </span>
                          <div className={`w-3 h-3 rounded-full ${
                            status === Severity.OPERATIONAL ? 'bg-emerald-500' :
                            status === Severity.DEGRADED ? 'bg-yellow-500' : 'bg-red-500'
                          }`}></div>
                        </div>
                      </div>
                      <UptimeGraph componentId={comp.id} />
                      <div className="flex justify-between mt-1 text-[10px] font-bold text-gray-400">
                         <span>SLA: 99.99%</span>
                         <span>90 DAY UPTIME</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        ))}
      </div>

      <footer className="mt-20 py-8 border-t border-gray-200 text-center text-sm text-gray-400">
        <p>&copy; {new Date().getFullYear()} StatusGuard Pro. Built for reliability.</p>
      </footer>
    </div>
  );
};

export default PublicDashboard;

import React, { useState } from 'react';
import { useApp } from '../store';
import { Severity } from '../types';
import { generateIncidentDescription } from '../services/geminiService';

const AdminDashboard: React.FC = () => {
  const { state, addRegion, removeRegion, addComponent, removeComponent, reportIncident, resolveIncident, logout } = useApp();
  const [newRegionName, setNewRegionName] = useState('');
  const [newCompData, setNewCompData] = useState({ regionId: '', name: '', desc: '' });
  const [incidentData, setIncidentData] = useState({ componentId: '', title: '', severity: Severity.DEGRADED, internalDesc: '' });
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAddRegion = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRegionName.trim()) {
      addRegion(newRegionName);
      setNewRegionName('');
    }
  };

  const handleAddComponent = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCompData.regionId && newCompData.name) {
      addComponent(newCompData.regionId, newCompData.name, newCompData.desc);
      setNewCompData({ regionId: '', name: '', desc: '' });
    }
  };

  const handleReportIncident = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);

    const component = state.regions.flatMap(r => r.components).find(c => c.id === incidentData.componentId);
    const publicDesc = await generateIncidentDescription(
      component?.name || 'Service',
      incidentData.severity,
      incidentData.internalDesc
    );

    reportIncident({
      componentId: incidentData.componentId,
      title: incidentData.title,
      description: publicDesc,
      severity: incidentData.severity,
      startTime: new Date().toISOString(),
      endTime: null,
    });

    setIncidentData({ componentId: '', title: '', severity: Severity.DEGRADED, internalDesc: '' });
    setIsGenerating(false);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-12">
      <div className="flex justify-between items-center mb-10">
        <h1 className="text-3xl font-bold">Admin Console</h1>
        <button onClick={logout} className="px-4 py-2 bg-gray-200 hover:bg-gray-300 rounded-lg text-sm font-medium transition-colors">
          Sign Out
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Management */}
        <div className="lg:col-span-2 space-y-8">
          {/* Incident Reporting Section */}
          <section className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
            <h2 className="text-xl font-bold mb-6 flex items-center gap-2 text-red-600">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
               Report New Incident
            </h2>
            <form onSubmit={handleReportIncident} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Component</label>
                  <select 
                    required
                    value={incidentData.componentId}
                    onChange={e => setIncidentData({...incidentData, componentId: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm"
                  >
                    <option value="">Select a component...</option>
                    {state.regions.flatMap(r => r.components.map(c => (
                      <option key={c.id} value={c.id}>{r.name} - {c.name}</option>
                    )))}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Severity</label>
                  <select 
                    value={incidentData.severity}
                    onChange={e => setIncidentData({...incidentData, severity: e.target.value as Severity})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm"
                  >
                    <option value={Severity.DEGRADED}>Degradation</option>
                    <option value={Severity.OUTAGE}>Total Outage</option>
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Incident Title</label>
                <input 
                  required
                  placeholder="e.g. Issues with User Login"
                  value={incidentData.title}
                  onChange={e => setIncidentData({...incidentData, title: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Internal Details (for AI Assistance)</label>
                <textarea 
                  required
                  placeholder="Describe the issue in detail... Gemini will help generate a user-facing update."
                  rows={3}
                  value={incidentData.internalDesc}
                  onChange={e => setIncidentData({...incidentData, internalDesc: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm"
                />
              </div>
              <button 
                disabled={isGenerating}
                className={`w-full py-3 rounded-lg text-white font-bold transition-all shadow-md ${
                  isGenerating ? 'bg-gray-400' : 'bg-red-600 hover:bg-red-700'
                }`}
              >
                {isGenerating ? 'Gemini is drafting public response...' : 'Post Incident'}
              </button>
            </form>
          </section>

          {/* Active Incidents List */}
          <section className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
            <h2 className="text-xl font-bold mb-4">Current Active Incidents</h2>
            <div className="space-y-3">
              {state.incidents.filter(i => !i.endTime).length === 0 ? (
                <p className="text-emerald-600 font-medium text-center py-4 bg-emerald-50 rounded-lg">No active incidents! All clear.</p>
              ) : (
                state.incidents.filter(i => !i.endTime).map(inc => (
                  <div key={inc.id} className="flex justify-between items-center p-4 border border-gray-100 rounded-lg hover:border-gray-300 transition-colors">
                    <div>
                      <h4 className="font-bold">{inc.title}</h4>
                      <p className="text-xs text-gray-500">{new Date(inc.startTime).toLocaleString()}</p>
                    </div>
                    <button 
                      onClick={() => resolveIncident(inc.id)}
                      className="px-3 py-1 bg-emerald-100 text-emerald-700 text-xs font-bold rounded hover:bg-emerald-200"
                    >
                      Resolve
                    </button>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Right Column: Configuration */}
        <div className="space-y-8">
          {/* Region Management */}
          <section className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
            <h2 className="font-bold mb-4 text-gray-800">Regions & Components</h2>

            <form onSubmit={handleAddRegion} className="mb-6">
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Add New Region</label>
              <div className="flex gap-2">
                <input 
                  value={newRegionName}
                  onChange={e => setNewRegionName(e.target.value)}
                  placeholder="Region Name"
                  className="flex-1 border border-gray-300 rounded px-3 py-1 text-sm"
                />
                <button className="px-3 py-1 bg-indigo-600 text-white rounded text-sm hover:bg-indigo-700 font-medium">Add</button>
              </div>
            </form>

            <div className="space-y-6">
              {state.regions.map(region => (
                <div key={region.id} className="border-t pt-4 first:border-t-0 first:pt-0">
                  <div className="flex justify-between items-center mb-3">
                    <h3 className="text-sm font-bold text-gray-700">{region.name}</h3>
                    <button onClick={() => removeRegion(region.id)} className="text-red-400 hover:text-red-600">
                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    </button>
                  </div>

                  <ul className="space-y-2 mb-3">
                    {region.components.map(c => (
                      <li key={c.id} className="flex justify-between items-center text-xs bg-gray-50 px-3 py-2 rounded">
                        <span>{c.name}</span>
                        <button onClick={() => removeComponent(region.id, c.id)} className="text-gray-400 hover:text-red-500">
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                        </button>
                      </li>
                    ))}
                  </ul>

                  <button 
                    onClick={() => setNewCompData({...newCompData, regionId: region.id})}
                    className="text-[10px] text-indigo-600 hover:underline font-bold uppercase"
                  >
                    + Add Component
                  </button>

                  {newCompData.regionId === region.id && (
                    <form onSubmit={handleAddComponent} className="mt-3 p-3 bg-gray-100 rounded space-y-2">
                      <input 
                        required
                        placeholder="Component Name"
                        className="w-full text-xs p-2 rounded"
                        value={newCompData.name}
                        onChange={e => setNewCompData({...newCompData, name: e.target.value})}
                      />
                      <input 
                        placeholder="Description"
                        className="w-full text-xs p-2 rounded"
                        value={newCompData.desc}
                        onChange={e => setNewCompData({...newCompData, desc: e.target.value})}
                      />
                      <div className="flex gap-2">
                        <button className="flex-1 py-1 bg-indigo-600 text-white text-xs rounded font-medium">Save</button>
                        <button type="button" onClick={() => setNewCompData({regionId: '', name: '', desc: ''})} className="flex-1 py-1 bg-white text-gray-500 text-xs rounded border">Cancel</button>
                      </div>
                    </form>
                  )}
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { AppProvider, useApp } from './store';
import PublicDashboard from './components/PublicDashboard';
import AdminDashboard from './components/AdminDashboard';

