export enum Severity {
  OPERATIONAL = 'OPERATIONAL',
  DEGRADED = 'DEGRADED', // degradation without loss of availability
  OUTAGE = 'OUTAGE'      // complete loss of availability
}

export interface Region {
  id: string;
  name: string;
}

export interface Service {
  id: string;
  regionId: string;
  name: string;
  description: string;
}

export interface Component {
  id: string;
  serviceId: string;
  name: string;
  description: string;
}

export interface Incident {
  id: string;
  componentId: string;
  title: string;
  description: string;
  severity: Severity;
  startTime: string; // ISO string
  endTime: string | null; // null if ongoing
}

export interface AppState {
  regions: Region[];
  services: Service[];
  components: Component[];
  incidents: Incident[];
  isAuthenticated: boolean;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { AppState, Region, Service, Component, Incident, Severity } from './types';

interface AppContextType {
  state: AppState;
  // Region CRUD
  addRegion: (name: string) => void;
  updateRegion: (id: string, name: string) => void;
  removeRegion: (id: string) => void;
  // Service CRUD
  addService: (regionId: string, name: string, description: string) => void;
  updateService: (id: string, name: string, description: string) => void;
  removeService: (id: string) => void;
  // Component CRUD
  addComponent: (serviceId: string, name: string, description: string) => void;
  updateComponent: (id: string, name: string, description: string) => void;
  removeComponent: (id: string) => void;
  // Incidents
  reportIncident: (incident: Omit<Incident, 'id'>) => void;
  resolveIncident: (incidentId: string) => void;
  login: () => void;
  logout: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const INITIAL_DATA: AppState = {
  regions: [
    { id: 'reg-1', name: 'Americas' },
    { id: 'reg-2', name: 'Europe' }
  ],
  services: [
    { id: 'ser-1', regionId: 'reg-1', name: 'Cloud Compute', description: 'Virtual Machine instances' },
    { id: 'ser-2', regionId: 'reg-1', name: 'Data Storage', description: 'Blob and Block storage' },
    { id: 'ser-3', regionId: 'reg-2', name: 'Edge Network', description: 'CDN and DNS services' }
  ],
  components: [
    { id: 'comp-1', serviceId: 'ser-1', name: 'API Gateway', description: 'Request routing' },
    { id: 'comp-2', serviceId: 'ser-1', name: 'Authentication', description: 'Login and Auth' },
    { id: 'comp-3', serviceId: 'ser-2', name: 'Storage Cluster A', description: 'Primary storage' }
  ],
  incidents: [],
  isAuthenticated: false,
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('statusguard_state_v2');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('statusguard_state_v2', JSON.stringify(state));
  }, [state]);

  // Regions
  const addRegion = useCallback((name: string) => {
    setState(prev => ({ ...prev, regions: [...prev.regions, { id: `reg-${Date.now()}`, name }] }));
  }, []);
  const updateRegion = useCallback((id: string, name: string) => {
    setState(prev => ({ ...prev, regions: prev.regions.map(r => r.id === id ? { ...r, name } : r) }));
  }, []);
  const removeRegion = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      regions: prev.regions.filter(r => r.id !== id),
      services: prev.services.filter(s => s.regionId !== id),
      components: prev.components.filter(c => !prev.services.find(s => s.regionId === id && s.id === c.serviceId))
    }));
  }, []);

  // Services
  const addService = useCallback((regionId: string, name: string, description: string) => {
    setState(prev => ({ ...prev, services: [...prev.services, { id: `ser-${Date.now()}`, regionId, name, description }] }));
  }, []);
  const updateService = useCallback((id: string, name: string, description: string) => {
    setState(prev => ({ ...prev, services: prev.services.map(s => s.id === id ? { ...s, name, description } : s) }));
  }, []);
  const removeService = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      services: prev.services.filter(s => s.id !== id),
      components: prev.components.filter(c => c.serviceId !== id)
    }));
  }, []);

  // Components
  const addComponent = useCallback((serviceId: string, name: string, description: string) => {
    setState(prev => ({ ...prev, components: [...prev.components, { id: `comp-${Date.now()}`, serviceId, name, description }] }));
  }, []);
  const updateComponent = useCallback((id: string, name: string, description: string) => {
    setState(prev => ({ ...prev, components: prev.components.map(c => c.id === id ? { ...c, name, description } : c) }));
  }, []);
  const removeComponent = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      components: prev.components.filter(c => c.id !== id),
      incidents: prev.incidents.filter(i => i.componentId !== id)
    }));
  }, []);

  // Incidents
  const reportIncident = useCallback((incident: Omit<Incident, 'id'>) => {
    setState(prev => ({ ...prev, incidents: [...prev.incidents, { ...incident, id: `inc-${Date.now()}` }] }));
  }, []);
  const resolveIncident = useCallback((incidentId: string) => {
    setState(prev => ({ ...prev, incidents: prev.incidents.map(inc => inc.id === incidentId ? { ...inc, endTime: new Date().toISOString() } : inc) }));
  }, []);

  const login = useCallback(() => setState(prev => ({ ...prev, isAuthenticated: true })), []);
  const logout = useCallback(() => setState(prev => ({ ...prev, isAuthenticated: false })), []);

  return (
    <AppContext.Provider value={{
      state, addRegion, updateRegion, removeRegion,
      addService, updateService, removeService,
      addComponent, updateComponent, removeComponent,
      reportIncident, resolveIncident, login, logout
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React from 'react';
import { useApp } from '../store';
import { Severity } from '../types';
import UptimeGraph from './UptimeGraph';

const PublicDashboard: React.FC = () => {
  const { state } = useApp();

  const getComponentStatus = (componentId: string) => {
    const activeIncidents = state.incidents.filter(i => i.componentId === componentId && !i.endTime);
    if (activeIncidents.find(i => i.severity === Severity.OUTAGE)) return Severity.OUTAGE;
    if (activeIncidents.find(i => i.severity === Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const getServiceStatus = (serviceId: string) => {
    const componentIds = state.components.filter(c => c.serviceId === serviceId).map(c => c.id);
    const statuses = componentIds.map(getComponentStatus);
    if (statuses.includes(Severity.OUTAGE)) return Severity.OUTAGE;
    if (statuses.includes(Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const globalStatus = React.useMemo(() => {
    const statuses = state.components.map(c => getComponentStatus(c.id));
    if (statuses.includes(Severity.OUTAGE)) return { label: 'System Outage', color: 'bg-red-600', sub: 'Major disruptions are occurring' };
    if (statuses.includes(Severity.DEGRADED)) return { label: 'Partial Degradation', color: 'bg-yellow-500', sub: 'Some services are experiencing issues' };
    return { label: 'All Systems Operational', color: 'bg-emerald-500', sub: 'Services are running optimally' };
  }, [state]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className={`${globalStatus.color} rounded-xl p-8 text-white shadow-lg mb-12`}>
        <h1 className="text-3xl font-bold mb-2">{globalStatus.label}</h1>
        <p className="opacity-90">{globalStatus.sub}</p>
      </div>

      {state.incidents.filter(i => !i.endTime).length > 0 && (
        <div className="mb-12">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
            Recent Updates
          </h2>
          <div className="space-y-4">
            {state.incidents.filter(i => !i.endTime).map(incident => (
              <div key={incident.id} className="bg-white border border-gray-200 rounded-lg p-6 shadow-sm">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg">{incident.title}</h3>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                    incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {incident.severity}
                  </span>
                </div>
                <p className="text-gray-600 mb-4">{incident.description}</p>
                <div className="text-xs text-gray-400">
                  Detected: {new Date(incident.startTime).toLocaleString()}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="space-y-12">
        {state.regions.map(region => (
          <div key={region.id}>
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b pb-2">{region.name}</h2>
            <div className="space-y-8">
              {state.services.filter(s => s.regionId === region.id).map(service => {
                const serviceStatus = getServiceStatus(service.id);
                return (
                  <div key={service.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-4 bg-gray-50 flex justify-between items-center border-b border-gray-100">
                      <div>
                        <h3 className="font-bold text-gray-700">{service.name}</h3>
                        <p className="text-[10px] text-gray-400 uppercase font-bold">{service.description}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold uppercase ${
                          serviceStatus === Severity.OPERATIONAL ? 'text-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'text-yellow-600' : 'text-red-600'
                        }`}>
                          {serviceStatus}
                        </span>
                        <div className={`w-2 h-2 rounded-full ${
                          serviceStatus === Severity.OPERATIONAL ? 'bg-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'bg-yellow-500' : 'bg-red-500'
                        }`}></div>
                      </div>
                    </div>
                    <div className="divide-y divide-gray-50">
                      {state.components.filter(c => c.serviceId === service.id).map(comp => {
                        const compStatus = getComponentStatus(comp.id);
                        return (
                          <div key={comp.id} className="p-6 hover:bg-gray-50 transition-colors">
                            <div className="flex justify-between items-center mb-3">
                              <div>
                                <h4 className="font-semibold text-gray-800 text-sm">{comp.name}</h4>
                                <p className="text-[10px] text-gray-400">{comp.description}</p>
                              </div>
                              <div className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                                compStatus === Severity.OPERATIONAL ? 'bg-emerald-50 text-emerald-600' :
                                compStatus === Severity.DEGRADED ? 'bg-yellow-50 text-yellow-600' : 'bg-red-50 text-red-600'
                              }`}>
                                {compStatus}
                              </div>
                            </div>
                            <UptimeGraph componentId={comp.id} />
                          </div>
                        );
                      })}
                      {state.components.filter(c => c.serviceId === service.id).length === 0 && (
                        <div className="p-4 text-center text-xs text-gray-400 italic">No components monitored for this service.</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

