// DB Configuration (Assumes env vars or defaults)
const pool = new Pool({
  connectionString: process.env.DATABASE_URL || 'postgresql://postgres:postgres@localhost:5432/statusguard',
});

// --- Database Initialization ---
const initDb = async () => {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS regions (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        name TEXT NOT NULL
      );
      CREATE TABLE IF NOT EXISTS services (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        region_id UUID REFERENCES regions(id) ON DELETE CASCADE,
        name TEXT NOT NULL,
        description TEXT
      );
      CREATE TABLE IF NOT EXISTS components (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        service_id UUID REFERENCES services(id) ON DELETE CASCADE,
        name TEXT NOT NULL,
        description TEXT
      );
      CREATE TABLE IF NOT EXISTS incidents (
        id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        component_id UUID REFERENCES components(id) ON DELETE CASCADE,
        title TEXT NOT NULL,
        description TEXT,
        severity TEXT NOT NULL,
        start_time TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
        end_time TIMESTAMP WITH TIME ZONE
      );
    `);

    // Seed data if empty
    const { rowCount } = await client.query('SELECT 1 FROM regions LIMIT 1');
    if (rowCount === 0) {
      const regRes = await client.query("INSERT INTO regions (name) VALUES ('Global Network') RETURNING id");
      const regId = regRes.rows[0].id;
      const serRes = await client.query(`INSERT INTO services (region_id, name, description) VALUES ('${regId}', 'Main API', 'Core connectivity layer') RETURNING id`);
      const serId = serRes.rows[0].id;
      await client.query(`INSERT INTO components (service_id, name, description) VALUES ('${serId}', 'Auth Gateway', 'Handles user sessions')`);
    }
  } finally {
    client.release();
  }
};

initDb();

