                </div>
              </div>
            )}

            {/* Component Editor */}
            {(compForm.serviceId !== '') && (
              <div className="bg-white p-6 rounded-xl border-2 border-indigo-500 shadow-xl">
                <h3 className="font-bold mb-4">{compForm.id ? 'Edit Component' : 'New Component'}</h3>
