import { GoogleGenAI } from "@google/genai";

// Initialize the Gemini API client using the environment variable.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a professional, reassuring, and concise public status update for a system incident.
 * Uses gemini-3-flash-preview for fast and efficient text generation.
 */
export const generatePublicDescription = async (componentName: string, severity: string, internalDesc: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Draft a professional, reassuring, and concise public status update for a status page based on this incident:
      - Impacted Component: ${componentName}
      - Severity: ${severity}
      - Internal Report: ${internalDesc}

      Requirements:
      - Use a professional and calm tone.
      - Be honest but reassuring.
      - Keep it under 2 sentences.
      - Do not include internal technical jargon.

      Return ONLY the public-facing text.`,
      config: {
        systemInstruction: "You are a senior site reliability engineer writing public status updates for a global infrastructure platform.",
        temperature: 0.7,
      }
    });

    // Directly access the .text property from GenerateContentResponse as per guidelines.
    return response.text?.trim() || `Update: ${componentName} is currently experiencing ${severity === 'OUTAGE' ? 'an outage' : 'degraded performance'}. Our engineers are investigating.`;
  } catch (error) {
    console.error("Gemini description generation failed:", error);
    // Fallback message in case of API failure.
    return `Update: ${componentName} is currently ${severity === 'OUTAGE' ? 'down' : 'experiencing issues'}. We are working to resolve this as quickly as possible.`;
  }
};

import express, { Request, Response, NextFunction } from 'express';
import { Pool } from 'pg';
import crypto from 'crypto';
import fs from 'fs';
import path from 'path';
// Import the Gemini service for drafting incident updates
import { generatePublicDescription } from './services/geminiService';

const app = express();
// FIX: Casting express.json() to any resolves the TypeScript error where NextHandleFunction is not matched to PathParams.
// This often happens due to version skew between @types/express and @types/body-parser.
app.use(express.json() as any);

// Database Pool
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
});

/**
 * PRODUCTION-READY SECURITY
 */
const hashPassword = (password: string): string => {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.scryptSync(password, salt, 64).toString('hex');
  return `${salt}:${hash}`;
};

const verifyPassword = (password: string, storedValue: string): boolean => {
  const [salt, hash] = storedValue.split(':');
  const derivedHash = crypto.scryptSync(password, salt, 64).toString('hex');
  return derivedHash === hash;
};

/**
 * SLA CALCULATION LOGIC
 * Calculates availability for the last 90 days.
 * Outage = 100% loss, Degradation = 50% loss for the duration.
 */
const calculateSLA = async (componentId: string, days = 90) => {
  const query = `
    SELECT severity, start_time, end_time 
    FROM incidents 
    WHERE component_id = $1 
    AND (end_time IS NULL OR end_time > NOW() - INTERVAL '${days} days')
  `;
  const { rows } = await pool.query(query, [componentId]);

  const totalSeconds = days * 24 * 60 * 60;
  const startTimeLimit = new Date();
  startTimeLimit.setDate(startTimeLimit.getDate() - days);

  let totalDowntimeSeconds = 0;

  rows.forEach(incident => {
    const start = new Date(Math.max(new Date(incident.start_time).getTime(), startTimeLimit.getTime()));
    const end = incident.end_time ? new Date(incident.end_time) : new Date();
    const durationSeconds = (end.getTime() - start.getTime()) / 1000;

    // Weighted downtime
    const weight = incident.severity === 'OUTAGE' ? 1.0 : 0.5;
    totalDowntimeSeconds += durationSeconds * weight;
  });

  const uptime = Math.max(0, totalSeconds - totalDowntimeSeconds);
  const percentage = (uptime / totalSeconds) * 100;
  return parseFloat(percentage.toFixed(4));
};

/**
 * DATABASE INITIALIZATION
 */
const initDb = async () => {
  const client = await pool.connect();
  try {
    const schemaFile = path.join(process.cwd(), 'schema.sql');
    const seedFile = path.join(process.cwd(), 'seed.sql');

    if (fs.existsSync(schemaFile)) {
      await client.query(fs.readFileSync(schemaFile, 'utf8'));
      console.log('Schema applied.');
    }

    // Only seed if empty
    const { rowCount } = await client.query('SELECT 1 FROM regions LIMIT 1');
    if (rowCount === 0 && fs.existsSync(seedFile)) {
      await client.query(fs.readFileSync(seedFile, 'utf8'));
      console.log('Seed data applied.');
    }
  } catch (err) {
    console.error('Database Init Error:', err);
