import React, { useState } from 'react';
import { Severity } from '../types.ts';
import { useApp } from '../store.tsx';

interface UptimeGraphProps {
  componentId: string;
  createdAt?: string;
  days?: number;
}

enum DailyStatus {
  OPERATIONAL = 'OPERATIONAL',
  DEGRADED = 'DEGRADED',
  OUTAGE = 'OUTAGE',
  DATA_MISSING = 'DATA_MISSING'
}

const UptimeGraph: React.FC<UptimeGraphProps> = ({ componentId, createdAt, days = 90 }) => {
  const { state } = useApp();
  const [hoveredDay, setHoveredDay] = useState<{index: number, status: DailyStatus} | null>(null);

  // Filter incidents for this component
  const componentIncidents = React.useMemo(() => {
    return state.incidents.filter(i => i.componentId === componentId);
  }, [state.incidents, componentId]);

  // Compute actual history based on component lifetime and incident logs
  const history = React.useMemo(() => {
    const creationTime = createdAt ? new Date(createdAt).getTime() : 0;

    return Array.from({ length: days }).map((_, i) => {
      // Index i=0 is 'days-1' days ago, i=days-1 is today
      const daysAgo = (days - 1) - i;
      const targetDate = new Date();
      targetDate.setHours(0, 0, 0, 0);
      targetDate.setDate(targetDate.getDate() - daysAgo);
      const targetTimeStart = targetDate.getTime();
      const targetTimeEnd = targetTimeStart + 24 * 60 * 60 * 1000;

      // Check if component existed on this day
      // We check if targetTimeEnd is before creationTime to mark missing data
      if (targetTimeEnd < creationTime) {
        return DailyStatus.DATA_MISSING;
      }

      // Check for incidents overlapping this day
      const dayIncidents = componentIncidents.filter(inc => {
        const incStart = new Date(inc.startTime).getTime();
        const incEnd = inc.endTime ? new Date(inc.endTime).getTime() : Date.now();

        // Incident overlaps if it starts before end of day AND ends after start of day
        return incStart < targetTimeEnd && incEnd > targetTimeStart;
      });

      if (dayIncidents.some(inc => inc.severity === Severity.OUTAGE)) return DailyStatus.OUTAGE;
      if (dayIncidents.some(inc => inc.severity === Severity.DEGRADED)) return DailyStatus.DEGRADED;

      return DailyStatus.OPERATIONAL;
    });
  }, [componentIncidents, createdAt, days]);

  const getDayColor = (status: DailyStatus) => {
    switch (status) {
      case DailyStatus.OUTAGE: return 'bg-red-500';
      case DailyStatus.DEGRADED: return 'bg-yellow-400';
      case DailyStatus.DATA_MISSING: return 'bg-gray-200';
      default: return 'bg-emerald-500';
    }
  };

  const getStatusLabel = (status: DailyStatus) => {
    switch (status) {
      case DailyStatus.OUTAGE: return 'Major Outage';
      case DailyStatus.DEGRADED: return 'Partial Degradation';
      case DailyStatus.DATA_MISSING: return 'No data';
      default: return 'Operational';
    }
  };

  const formatDate = (daysAgo: number) => {
    const date = new Date();
    date.setDate(date.getDate() - daysAgo);
    return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
  };

  return (
    <div className="mt-2 relative">
      {/* Custom Tooltip */}
      {hoveredDay && (
        <div 
          className="absolute z-50 bottom-full mb-2 bg-gray-900 text-white text-[10px] px-2 py-1.5 rounded-md shadow-xl whitespace-nowrap pointer-events-none animate-in fade-in zoom-in-95 duration-100 flex flex-col items-center"
          style={{ 
            left: `${(hoveredDay.index / (days - 1)) * 100}%`,
            transform: 'translateX(-50%)'
          }}
        >
          <span className="font-bold opacity-70 mb-0.5">{formatDate(days - 1 - hoveredDay.index)}</span>
          <div className="flex items-center gap-1.5">
            <span className={`w-1.5 h-1.5 rounded-full ${getDayColor(hoveredDay.status)} shadow-[0_0_4px_rgba(0,0,0,0.5)]`}></span>
            <span className="capitalize font-medium">{getStatusLabel(hoveredDay.status)}</span>
          </div>
          {/* Tooltip Arrow */}
          <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-900"></div>
        </div>
      )}

      <div className="flex gap-[2px] h-8 items-end">
        {history.map((status, i) => (
          <div
            key={i}
            onMouseEnter={() => setHoveredDay({ index: i, status })}
            onMouseLeave={() => setHoveredDay(null)}
            className={`flex-1 h-full rounded-[1px] ${getDayColor(status)} opacity-80 hover:opacity-100 transition-opacity cursor-help`}
          />
        ))}
      </div>
      <div className="flex justify-between mt-1 text-[10px] text-gray-400 font-medium">
        <span>{days} days ago</span>
        <span className="text-gray-300 mx-1">|</span>
        <span>Today</span>
      </div>
    </div>
  );
};

export default UptimeGraph;

import React from 'react';
import { useApp } from '../store.tsx';
import { Severity } from '../types.ts';
import UptimeGraph from './UptimeGraph.tsx';

const PublicDashboard: React.FC = () => {
  const { state } = useApp();

  const getComponentStatus = (componentId: string) => {
    const activeIncidents = state.incidents.filter(i => i.componentId === componentId && !i.endTime);
    if (activeIncidents.find(i => i.severity === Severity.OUTAGE)) return Severity.OUTAGE;
    if (activeIncidents.find(i => i.severity === Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const getServiceStatus = (serviceId: string) => {
    const componentIds = state.components.filter(c => c.serviceId === serviceId).map(c => c.id);
    if (componentIds.length === 0) return Severity.OPERATIONAL;
    const statuses = componentIds.map(getComponentStatus);
    if (statuses.includes(Severity.OUTAGE)) return Severity.OUTAGE;
    if (statuses.includes(Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const globalStatus = React.useMemo(() => {
    if (state.components.length === 0) return { label: 'System Initializing', color: 'bg-indigo-500', sub: 'Monitoring is starting up...' };
    const statuses = state.components.map(c => getComponentStatus(c.id));
    if (statuses.includes(Severity.OUTAGE)) return { label: 'System Outage', color: 'bg-red-600', sub: 'Major disruptions are occurring' };
    if (statuses.includes(Severity.DEGRADED)) return { label: 'Partial Degradation', color: 'bg-yellow-500', sub: 'Some services are experiencing issues' };
    return { label: 'All Systems Operational', color: 'bg-emerald-500', sub: 'Services are running optimally' };
  }, [state]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className={`${globalStatus.color} rounded-xl p-8 text-white shadow-lg mb-12 transition-all duration-500`}>
        <h1 className="text-3xl font-bold mb-2">{globalStatus.label}</h1>
        <p className="opacity-90">{globalStatus.sub}</p>
      </div>

      {state.incidents.filter(i => !i.endTime).length > 0 && (
        <div className="mb-12">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
            Active Incidents
          </h2>
          <div className="space-y-4">
            {state.incidents.filter(i => !i.endTime).map(incident => (
              <div key={incident.id} className="bg-white border-l-4 border-red-500 rounded-lg p-6 shadow-sm">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg">{incident.title}</h3>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                    incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {incident.severity}
                  </span>
                </div>
                <p className="text-gray-600 mb-4">{incident.description}</p>
                <div className="text-xs text-gray-400">
                  Detected: {new Date(incident.startTime).toLocaleString()}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="space-y-12">
        {state.regions.map(region => (
          <div key={region.id}>
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b pb-2">{region.name}</h2>
            <div className="space-y-8">
              {state.services.filter(s => s.regionId === region.id).map(service => {
                const serviceStatus = getServiceStatus(service.id);
                return (
                  <div key={service.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-4 bg-gray-50 flex justify-between items-center border-b border-gray-100">
                      <div>
                        <h3 className="font-bold text-gray-700">{service.name}</h3>
                        <p className="text-[10px] text-gray-400 uppercase font-bold">{service.description}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold uppercase ${
                          serviceStatus === Severity.OPERATIONAL ? 'text-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'text-yellow-600' : 'text-red-600'
                        }`}>
                          {serviceStatus}
                        </span>
                        <div className={`w-2 h-2 rounded-full ${
                          serviceStatus === Severity.OPERATIONAL ? 'bg-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'bg-yellow-500' : 'bg-red-500'
                        }`}></div>
                      </div>
                    </div>
                    <div className="divide-y divide-gray-50">
                      {state.components.filter(c => c.serviceId === service.id).map(comp => {
                        const compStatus = getComponentStatus(comp.id);
                        return (
                          <div key={comp.id} className="p-6 hover:bg-gray-50 transition-colors">
                            <div className="flex justify-between items-center mb-3">
                              <div>
                                <h4 className="font-semibold text-gray-800 text-sm flex items-center gap-2">
                                  {comp.name}
                                  <span className="text-[10px] text-gray-400 font-medium bg-gray-100 px-1.5 py-0.5 rounded">
                                    90D SLA: {comp.sla90 ?? 100}%
                                  </span>
                                </h4>
                                <p className="text-[10px] text-gray-400">{comp.description}</p>
                              </div>
                              <div className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                                compStatus === Severity.OPERATIONAL ? 'bg-emerald-50 text-emerald-600' :
                                compStatus === Severity.DEGRADED ? 'bg-yellow-50 text-yellow-600' : 'bg-red-50 text-red-600'
                              }`}>
                                {compStatus}
                              </div>
                            </div>
                            <UptimeGraph componentId={comp.id} createdAt={comp.createdAt} />
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PublicDashboard;

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- Users table for authentication
CREATE TABLE IF NOT EXISTS users (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    username TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Regions table
CREATE TABLE IF NOT EXISTS regions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Services table
CREATE TABLE IF NOT EXISTS services (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    region_id UUID REFERENCES regions(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    description TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Components table
CREATE TABLE IF NOT EXISTS components (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    service_id UUID REFERENCES services(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    description TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Incidents table
CREATE TABLE IF NOT EXISTS incidents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    component_id UUID REFERENCES components(id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    description TEXT,
    severity TEXT NOT NULL,
    start_time TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    end_time TIMESTAMP WITH TIME ZONE
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_services_region ON services(region_id);
CREATE INDEX IF NOT EXISTS idx_components_service ON components(service_id);
CREATE INDEX IF NOT EXISTS idx_incidents_component ON incidents(component_id);
CREATE INDEX IF NOT EXISTS idx_incidents_active ON incidents(end_time) WHERE end_time IS NULL;
